from pydantic_ai import Agent, ResultValidator
from vex_sdk import Vex

vex = Vex(api_key="your-vex-key")

def ferpa_validator(result: str) -> bool:
    policy = vex.policy("education-ferpa-pii-block")
    return policy.validate(result)

class StudentTutor(Agent):
    def grade_essay(self, essay: str, student_id: str) -> str:
        return self._call_llm(f"Grade essay for student {student_id}: {essay}")

    result_validator = ResultValidator(ferpa_validator)

tutor = StudentTutor()
